type AdminIconProps = {
  readonly name: AdminIconName
  readonly size?: number
}

export function AdminIcon({ name, size }: AdminIconProps) {
  const icon = iconDefinitions[name]
  const width = size ?? icon.width
  const height = size ? (size * icon.height) / icon.width : icon.height

  return (
    <svg
      aria-hidden="true"
      fill="none"
      focusable="false"
      height={height}
      stroke="currentColor"
      strokeLinecap="round"
      strokeLinejoin="round"
      strokeWidth={icon.strokeWidth}
      viewBox={icon.viewBox}
      width={width}
      xmlns="http://www.w3.org/2000/svg"
    >
      {icon.glyph}
    </svg>
  )
}
